          shopSurplusPurchasesEnabled: translate("HWHAUTO_TOOLTIP_SHOP_SURPLUS"),
          autoEquipCraftedItems: translate("HWHAUTO_TOOLTIP_AUTO_EQUIP"),
          autoPromoteHeroes: translate("HWHAUTO_TOOLTIP_AUTO_PROMOTE"),
          craftAfterFarm: translate("HWHAUTO_TOOLTIP_CRAFT_AFTER_FARM"),
          promoteAfterFarm: translate("HWHAUTO_TOOLTIP_PROMOTE_AFTER_FARM"),
          craftDebugConsole: translate("HWHAUTO_TOOLTIP_CRAFT_DEBUG"),
