          debugSelectSaveConsole: translate("HWHAUTO_TOOLTIP_DEBUG_SELECT_SAVE"),
          showSettingsCoinAmounts: translate("HWHAUTO_TOOLTIP_SETTINGS_COIN_AMOUNTS"),
