          collectDailyQuestStamina: translate("HWHAUTO_TOOLTIP_DAILY_QUEST_STAMINA"),
          collectGuildQuestEnergy: translate("HWHAUTO_TOOLTIP_GUILD_QUEST"),
          collectMailStamina: translate("HWHAUTO_TOOLTIP_MAIL_STAMINA"),
