          exportSettings: translate("HWHAUTO_SETTINGS_EXPORT_JSON_TITLE"),
          importSettings: translate("HWHAUTO_SETTINGS_IMPORT_JSON_TITLE"),
          dumpGameLibrary: translate("HWHAUTO_SETTINGS_DUMP_GAME_LIBRARY_TITLE"),
